# rbac_core.py
from dataclasses import dataclass
from enum import Enum
from functools import wraps
from typing import Callable, Any
import logging
import time

logger = logging.getLogger(__name__)


class Permission(str, Enum):
    READ = "read"
    WRITE = "write"
    EXEC = "exec"
    CALL_EXTERNAL = "call_external"
    SPAWN_AGENT = "spawn_agent"


# Role definitions: role name -> set of permissions
ROLE_PERMISSIONS: dict[str, set[Permission]] = {
    "admin": {
        Permission.READ,
        Permission.WRITE,
        Permission.EXEC,
        Permission.CALL_EXTERNAL,
        Permission.SPAWN_AGENT,
    },
    "writer": {
        Permission.READ,
        Permission.WRITE,
        Permission.CALL_EXTERNAL,
    },
    "reader": {
        Permission.READ,
    },
    "analyst": {
        Permission.READ,
        Permission.CALL_EXTERNAL,
    },
}


@dataclass(frozen=True)  # frozen=True makes the identity immutable
class AgentIdentity:
    agent_id: str
    role: str
    session_id: str
    parent_agent_id: str | None = None

    def has_permission(self, permission: Permission) -> bool:
        return permission in ROLE_PERMISSIONS.get(self.role, set())

    def permissions(self) -> set[Permission]:
        return ROLE_PERMISSIONS.get(self.role, set())


class AuthorizationError(PermissionError):
    """Raised when an agent attempts to use a tool it is not permitted to access."""
    def __init__(self, agent_id: str, role: str, tool: str, required: set[Permission]):
        self.agent_id = agent_id
        self.role = role
        self.tool = tool
        self.required = required
        super().__init__(
            f"Agent '{agent_id}' (role='{role}') lacks permissions "
            f"{[p.value for p in required]} required for tool '{tool}'"
        )


def requires(*permissions: Permission) -> Callable:
    """Decorator that enforces RBAC on a tool function.

    The first positional argument of the decorated function must be an
    AgentIdentity instance, or 'agent' must be passed as a keyword argument.
    """
    required_set = set(permissions)

    def decorator(fn: Callable) -> Callable:
        fn.required_permissions = required_set  # attach for introspection

        @wraps(fn)
        def wrapper(*args, **kwargs) -> Any:
            agent: AgentIdentity | None = None
            if args and isinstance(args[0], AgentIdentity):
                agent = args[0]
            elif "agent" in kwargs and isinstance(kwargs["agent"], AgentIdentity):
                agent = kwargs["agent"]

            if agent is None:
                raise ValueError(
                    f"Tool '{fn.__name__}' decorated with @requires() must receive "
                    "an AgentIdentity as first argument or 'agent' keyword."
                )

            missing = required_set - agent.permissions()
            decision = "allow" if not missing else "deny"

            logger.info(
                "rbac_decision",
                extra={
                    "agent_id": agent.agent_id,
                    "role": agent.role,
                    "session_id": agent.session_id,
                    "tool": fn.__name__,
                    "required_permissions": sorted(p.value for p in required_set),
                    "decision": decision,
                    "ts": time.time(),
                },
            )

            if missing:
                raise AuthorizationError(
                    agent_id=agent.agent_id,
                    role=agent.role,
                    tool=fn.__name__,
                    required=missing,
                )

            return fn(*args, **kwargs)

        return wrapper
    return decorator

