from rbac_core import AgentIdentity, Permission, requires, AuthorizationError


@requires(Permission.READ)
def search_documents(agent: AgentIdentity, query: str, top_k: int = 5) -> list[dict]:
    """Search the document store. Available to all roles."""
    print(f"[{agent.role}] Searching for: {query}")
    return [{"id": "doc-1", "content": "Example result", "score": 0.92}]


@requires(Permission.WRITE)
def update_record(agent: AgentIdentity, record_id: str, updates: dict) -> dict:
    """Update a record. Requires write permission."""
    print(f"[{agent.role}] Updating record {record_id}")
    return {"status": "ok", "record_id": record_id}


@requires(Permission.EXEC)
def execute_code(agent: AgentIdentity, code: str, timeout: int = 30) -> str:
    """Execute Python code in a sandbox. Requires exec permission."""
    print(f"[{agent.role}] Executing code (len={len(code)})")
    return "# execution output"


@requires(Permission.CALL_EXTERNAL, Permission.WRITE)
def send_notification(agent: AgentIdentity, channel: str, message: str) -> bool:
    """Send a notification via external API. Requires call_external + write."""
    print(f"[{agent.role}] Sending notification to {channel}")
    return True


# --- Demo ---
if __name__ == "__main__":
    admin = AgentIdentity("orch-001", "admin", "sess-abc", parent_agent_id=None)
    reader = AgentIdentity("analyst-002", "reader", "sess-abc", parent_agent_id="orch-001")

    # Admin can use all tools
    search_documents(admin, "quarterly report")
    update_record(admin, "rec-42", {"status": "reviewed"})
    execute_code(admin, "print('hello')")
    print("Admin succeeded on all tools")

    # Reader can only search
    results = search_documents(reader, "compliance policy")
    print(f"Reader search succeeded: {results[0]['id']}")

    try:
        update_record(reader, "rec-42", {"status": "modified"})
    except AuthorizationError as e:
        print(f"Reader correctly blocked from write: {e}")

    try:
        execute_code(reader, "import os; os.system('ls')")
    except AuthorizationError as e:
        print(f"Reader correctly blocked from exec: {e}")

# legal_tech_agents.py — JWT-based agent identity for a legal-tech pipeline
import jwt
from datetime import datetime, timedelta, timezone
from rbac_core import AgentIdentity, ROLE_PERMISSIONS, Permission

JWT_SECRET = "use-a-real-secret-key-in-production"
JWT_ALGO   = "HS256"

# Domain-specific roles.  Neither has CALL_EXTERNAL — structural exfiltration barrier.
ROLE_PERMISSIONS["reviewer"] = {Permission.READ}
ROLE_PERMISSIONS["drafter"]  = {Permission.READ, Permission.WRITE}

def issue_agent_token(agent_id, role, session_id, parent_agent_id=None, ttl=30):
    now = datetime.now(timezone.utc)
    payload = {"sub": agent_id, "role": role, "session_id": session_id,
               "parent_agent_id": parent_agent_id,
               "iat": now, "exp": now + timedelta(minutes=ttl)}
    return jwt.encode(payload, JWT_SECRET, algorithm=JWT_ALGO)

def verify_agent_token(token) -> AgentIdentity:
    payload = jwt.decode(token, JWT_SECRET, algorithms=[JWT_ALGO])
    return AgentIdentity(agent_id=payload["sub"], role=payload["role"],
                         session_id=payload["session_id"],
                         parent_agent_id=payload.get("parent_agent_id"))

# WRONG: agent inherits user role directly
def spawn_agent_for_user(user_role: str, session_id: str) -> AgentIdentity:
    return AgentIdentity(
        agent_id="agent-001",
        role=user_role,       # Admin user -> admin agent -- dangerous!
        session_id=session_id,
    )

# RIGHT: agent is assigned the minimum role needed for its specific task,
# regardless of who triggered it.
def spawn_document_reviewer(session_id: str, parent_id: str) -> AgentIdentity:
    return AgentIdentity(
        agent_id="rev-001",
        role="reviewer",       # Task-appropriate role, not the user's role
        session_id=session_id,
        parent_agent_id=parent_id,
    )

# WRONG: checking permissions inside the tool implementation
def delete_record_bad(agent: AgentIdentity, record_id: str) -> None:
    if agent.role not in ["admin", "writer"]:  # easy to forget or bypass
        raise PermissionError("Insufficient permissions")
    _do_delete(record_id)

# RIGHT: permission enforced by decorator, unconditionally, at dispatch
@requires(Permission.WRITE)
def delete_record(agent: AgentIdentity, record_id: str) -> None:
    _do_delete(record_id)  # can only be reached if agent has WRITE permission
